(game "Precise Holistic Pudu"
    (players 2)
    (equipment
        (board (square 9))
    )
    (rules
        (play
            (repeat (P1 P2)
                (place
                    (destination empty)
                    (result
                        (or
                            (not (exists (occupied mover)))  // First move exception
                            (exists
                                (and
                                    (adjacent (occupied mover))
                                    (not (custodial 1 mover))  // Prevents isolation violation
                                )
                            )
                        )
                    )
                    (effects
                        (set_score mover
                            (count
                                (and
                                    (line 7 exact:true)
                                    (custodial 1 mover not)  // Isolation check
                                )
                            )
                        )
                        (set_score opponent
                            (count
                                (and
                                    (line 7 exact:true)
                                    (custodial 1 opponent not)
                                )
                            )
                        )
                    )
                )
            )
        )
        (end
            (if (full_board) (by_score))
        )
    )
)

(game "Precise Holistic Pudu"
    (players 2)
    (equipment
        (board (square 9))
    )
    (rules
        (play
            (once_through (P1)
                (place (destination center))
            )
            (repeat (P2 P1)
                (place
                    (destination
                        (and
                            empty
                            (or
                                (adjacent (occupied mover))
                                (edge any)  // Edge placement allowed
                            )
                        )
                    )
                    (result
                        (or
                            (not (exists (occupied mover)))
                            (exists
                                (and
                                    (adjacent (occupied mover))
                                    (not (custodial 1 mover))
                                )
                            )
                        )
                    )
                    (effects
                        (set_score mover
                            (count
                                (and
                                    (line 7 exact:true)
                                    (custodial 1 mover not)
                                    (connected
                                        (corners)
                                        mover
                                        orientation:orthogonal
                                    )
                                )
                            )
                        )
                        (set_score opponent
                            (count
                                (and
                                    (line 7 exact:true)
                                    (custodial 1 opponent not)
                                    (connected
                                        (corners)
                                        opponent
                                        orientation:orthogonal
                                    )
                                )
                            )
                        )
                    )
                )
            )
        )
        (end
            (if (full_board) (by_score))
            (if (and
                (>= (score mover) 3)
                (>= (connected (corners) mover) 2)
            ) (mover win))
        )
    )
    (rendering
        (color P1 black)
        (color P2 white)
    )
)

